#!/usr/bin/env python3
"""
Stop hook for do skill workflow.

Checks if the do loop is complete before allowing exit.
Uses the new task directory structure under .claude/do-tasks/.
"""

import glob
import json
import os
import sys

DIR_TASKS = ".claude/do-tasks"
FILE_CURRENT_TASK = ".current-task"
FILE_TASK_JSON = "task.json"

PHASE_NAMES = {
    1: "Understand",
    2: "Clarify",
    3: "Design",
    4: "Implement",
    5: "Complete",
}


def phase_name_for(n: int) -> str:
    return PHASE_NAMES.get(n, f"Phase {n}")


def get_current_task(project_dir: str) -> str | None:
    """Read current task directory path."""
    current_task_file = os.path.join(project_dir, DIR_TASKS, FILE_CURRENT_TASK)
    if not os.path.exists(current_task_file):
        return None
    try:
        with open(current_task_file, "r", encoding="utf-8") as f:
            content = f.read().strip()
            return content if content else None
    except Exception:
        return None


def get_task_info(project_dir: str, task_dir: str) -> dict | None:
    """Read task.json data."""
    task_json_path = os.path.join(project_dir, task_dir, FILE_TASK_JSON)
    if not os.path.exists(task_json_path):
        return None
    try:
        with open(task_json_path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return None


def check_task_complete(project_dir: str, task_dir: str) -> str:
    """Check if task is complete. Returns blocking reason or empty string."""
    task_info = get_task_info(project_dir, task_dir)
    if not task_info:
        return ""

    status = task_info.get("status", "")
    if status == "completed":
        return ""

    current_phase = task_info.get("current_phase", 1)
    max_phases = task_info.get("max_phases", 5)
    phase_name = task_info.get("phase_name", phase_name_for(current_phase))
    completion_promise = task_info.get("completion_promise", "<promise>DO_COMPLETE</promise>")

    if current_phase >= max_phases:
        # Task is at final phase, allow exit
        return ""

    return (
        f"do loop incomplete: current phase {current_phase}/{max_phases} ({phase_name}). "
        f"Continue with remaining phases; use 'task.py update-phase <N>' after each phase. "
        f"Include completion_promise in final output when done: {completion_promise}. "
        f"To exit early, set status to 'completed' in task.json."
    )


def main():
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", os.getcwd())

    task_dir = get_current_task(project_dir)
    if not task_dir:
        # No active task, allow exit
        sys.exit(0)

    stdin_payload = ""
    if not sys.stdin.isatty():
        try:
            stdin_payload = sys.stdin.read()
        except Exception:
            pass

    reason = check_task_complete(project_dir, task_dir)
    if not reason:
        sys.exit(0)

    print(json.dumps({"decision": "block", "reason": reason}))
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
Verify Loop Hook for do skill workflow.

SubagentStop hook that intercepts when code-reviewer agent tries to stop.
Runs verification commands to ensure code quality before allowing exit.

Mechanism:
- Intercepts SubagentStop event for code-reviewer agent
- Runs verify commands from task.json if configured
- Blocks stopping until verification passes
- Has max iterations as safety limit (MAX_ITERATIONS=5)

State file: .claude/do-tasks/.verify-state.json
"""

import json
import os
import subprocess
import sys
from datetime import datetime
from pathlib import Path

# Configuration
MAX_ITERATIONS = 5
STATE_TIMEOUT_MINUTES = 30
DIR_TASKS = ".claude/do-tasks"
FILE_CURRENT_TASK = ".current-task"
FILE_TASK_JSON = "task.json"
STATE_FILE = ".claude/do-tasks/.verify-state.json"

# Only control loop for code-reviewer agent
TARGET_AGENTS = {"code-reviewer"}


def get_project_root(cwd: str) -> str | None:
    """Find project root (directory with .claude folder)."""
    current = Path(cwd).resolve()
    while current != current.parent:
        if (current / ".claude").exists():
            return str(current)
        current = current.parent
    return None


def get_current_task(project_root: str) -> str | None:
    """Read current task directory path."""
    current_task_file = os.path.join(project_root, DIR_TASKS, FILE_CURRENT_TASK)
    if not os.path.exists(current_task_file):
        return None
    try:
        with open(current_task_file, "r", encoding="utf-8") as f:
            content = f.read().strip()
            return content if content else None
    except Exception:
        return None


def get_task_info(project_root: str, task_dir: str) -> dict | None:
    """Read task.json data."""
    task_json_path = os.path.join(project_root, task_dir, FILE_TASK_JSON)
    if not os.path.exists(task_json_path):
        return None
    try:
        with open(task_json_path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return None


def get_verify_commands(task_info: dict) -> list[str]:
    """Get verify commands from task.json."""
    return task_info.get("verify_commands", [])


def run_verify_commands(project_root: str, commands: list[str]) -> tuple[bool, str]:
    """Run verify commands and return (success, message)."""
    for cmd in commands:
        try:
            result = subprocess.run(
                cmd,
                shell=True,
                cwd=project_root,
                capture_output=True,
                timeout=120,
            )
            if result.returncode != 0:
                stderr = result.stderr.decode("utf-8", errors="replace")
                stdout = result.stdout.decode("utf-8", errors="replace")
                error_output = stderr or stdout
                if len(error_output) > 500:
                    error_output = error_output[:500] + "..."
                return False, f"Command failed: {cmd}\n{error_output}"
        except subprocess.TimeoutExpired:
            return False, f"Command timed out: {cmd}"
        except Exception as e:
            return False, f"Command error: {cmd} - {str(e)}"
    return True, "All verify commands passed"


def load_state(project_root: str) -> dict:
    """Load verify loop state."""
    state_path = os.path.join(project_root, STATE_FILE)
    if not os.path.exists(state_path):
        return {"task": None, "iteration": 0, "started_at": None}
    try:
        with open(state_path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {"task": None, "iteration": 0, "started_at": None}


def save_state(project_root: str, state: dict) -> None:
    """Save verify loop state."""
    state_path = os.path.join(project_root, STATE_FILE)
    try:
        os.makedirs(os.path.dirname(state_path), exist_ok=True)
        with open(state_path, "w", encoding="utf-8") as f:
            json.dump(state, f, indent=2, ensure_ascii=False)
    except Exception:
        pass


def main():
    try:
        input_data = json.load(sys.stdin)
    except json.JSONDecodeError:
        sys.exit(0)

    hook_event = input_data.get("hook_event_name", "")
    if hook_event != "SubagentStop":
        sys.exit(0)

    subagent_type = input_data.get("subagent_type", "")
    agent_output = input_data.get("agent_output", "")
    cwd = input_data.get("cwd", os.getcwd())

    if subagent_type not in TARGET_AGENTS:
        sys.exit(0)

    project_root = get_project_root(cwd)
    if not project_root:
        sys.exit(0)

    task_dir = get_current_task(project_root)
    if not task_dir:
        sys.exit(0)

    task_info = get_task_info(project_root, task_dir)
    if not task_info:
        sys.exit(0)

    verify_commands = get_verify_commands(task_info)
    if not verify_commands:
        # No verify commands configured, allow exit
        sys.exit(0)

    # Load state
    state = load_state(project_root)

    # Reset state if task changed or too old
    should_reset = False
    if state.get("task") != task_dir:
        should_reset = True
    elif state.get("started_at"):
        try:
            started = datetime.fromisoformat(state["started_at"])
            if (datetime.now() - started).total_seconds() > STATE_TIMEOUT_MINUTES * 60:
                should_reset = True
        except (ValueError, TypeError):
            should_reset = True

    if should_reset:
        state = {
            "task": task_dir,
            "iteration": 0,
            "started_at": datetime.now().isoformat(),
        }

    # Increment iteration
    state["iteration"] = state.get("iteration", 0) + 1
    current_iteration = state["iteration"]
    save_state(project_root, state)

    # Safety check: max iterations
    if current_iteration >= MAX_ITERATIONS:
        state["iteration"] = 0
        save_state(project_root, state)
        output = {
            "decision": "allow",
            "reason": f"Max iterations ({MAX_ITERATIONS}) reached. Stopping to prevent infinite loop.",
        }
        print(json.dumps(output, ensure_ascii=False))
        sys.exit(0)

    # Run verify commands
    passed, message = run_verify_commands(project_root, verify_commands)

    if passed:
        state["iteration"] = 0
        save_state(project_root, state)
        output = {
            "decision": "allow",
            "reason": "All verify commands passed. Review phase complete.",
        }
        print(json.dumps(output, ensure_ascii=False))
        sys.exit(0)
    else:
        output = {
            "decision": "block",
            "reason": f"Iteration {current_iteration}/{MAX_ITERATIONS}. Verification failed:\n{message}\n\nPlease fix the issues and try again.",
        }
        print(json.dumps(output, ensure_ascii=False))
        sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Install/uninstall do skill to ~/.claude/skills/do"""
import argparse
import json
import os
import shutil
import sys
from pathlib import Path

SKILL_NAME = "do"
HOOK_PATH = "~/.claude/skills/do/hooks/stop-hook.py"

MODELS_JSON_TEMPLATE = {
    "agents": {
        "code-explorer": {
            "backend": "claude",
            "model": "claude-sonnet-4-5-20250929"
        },
        "code-architect": {
            "backend": "claude",
            "model": "claude-sonnet-4-5-20250929"
        },
        "code-reviewer": {
            "backend": "claude",
            "model": "claude-sonnet-4-5-20250929"
        }
    }
}

def get_settings_path() -> Path:
    return Path.home() / ".claude" / "settings.json"

def load_settings() -> dict:
    path = get_settings_path()
    if path.exists():
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    return {}

def save_settings(settings: dict):
    path = get_settings_path()
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(settings, f, indent=2)

def add_hook(settings: dict) -> dict:
    hook_command = str(Path(HOOK_PATH).expanduser())
    hook_entry = {
        "type": "command",
        "command": f"python3 {hook_command}"
    }

    if "hooks" not in settings:
        settings["hooks"] = {}
    if "Stop" not in settings["hooks"]:
        settings["hooks"]["Stop"] = []

    stop_hooks = settings["hooks"]["Stop"]

    for item in stop_hooks:
        if "hooks" in item:
            for h in item["hooks"]:
                if "stop-hook" in h.get("command", "") and "do" in h.get("command", ""):
                    h["command"] = f"python3 {hook_command}"
                    return settings

    stop_hooks.append({"hooks": [hook_entry]})
    return settings

def remove_hook(settings: dict) -> dict:
    if "hooks" not in settings or "Stop" not in settings["hooks"]:
        return settings

    stop_hooks = settings["hooks"]["Stop"]
    new_stop_hooks = []

    for item in stop_hooks:
        if "hooks" in item:
            filtered = [h for h in item["hooks"]
                       if "stop-hook" not in h.get("command", "")
                       or "do" not in h.get("command", "")]
            if filtered:
                item["hooks"] = filtered
                new_stop_hooks.append(item)
        else:
            new_stop_hooks.append(item)

    settings["hooks"]["Stop"] = new_stop_hooks
    if not settings["hooks"]["Stop"]:
        del settings["hooks"]["Stop"]
    if not settings["hooks"]:
        del settings["hooks"]

    return settings

def install_models_json():
    """Install ~/.codeagent/models.json if not exists"""
    path = Path.home() / ".codeagent" / "models.json"
    if path.exists():
        print(f"⚠ {path} already exists, skipping")
        return

    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(MODELS_JSON_TEMPLATE, f, indent=2)
    print(f"✓ Created {path}")

def install():
    src = Path(__file__).parent.resolve()
    dest = Path.home() / ".claude" / "skills" / SKILL_NAME

    dest.mkdir(parents=True, exist_ok=True)

    exclude = {".git", "__pycache__", ".DS_Store", "install.py"}

    for item in src.iterdir():
        if item.name in exclude:
            continue
        target = dest / item.name
        if target.exists():
            if target.is_dir():
                shutil.rmtree(target)
            else:
                target.unlink()
        if item.is_dir():
            shutil.copytree(item, target)
        else:
            shutil.copy2(item, target)

    settings = load_settings()
    settings = add_hook(settings)
    save_settings(settings)

    install_models_json()

    print(f"✓ Installed to {dest}")
    print(f"✓ Hook added to settings.json")

def uninstall():
    dest = Path.home() / ".claude" / "skills" / SKILL_NAME

    settings = load_settings()
    settings = remove_hook(settings)
    save_settings(settings)
    print(f"✓ Hook removed from settings.json")

    if dest.exists():
        shutil.rmtree(dest)
        print(f"✓ Removed {dest}")
    else:
        print(f"⚠ {dest} not found")

def main():
    parser = argparse.ArgumentParser(description="Install/uninstall do skill")
    parser.add_argument("--uninstall", "-u", action="store_true", help="Uninstall the skill")
    args = parser.parse_args()

    if args.uninstall:
        uninstall()
    else:
        install()

if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
Get context for current task.

Reads the current task's jsonl files and returns context for specified agent.
Used by inject-context hook to build agent prompts.
"""

import json
import os
import sys
from pathlib import Path

DIR_TASKS = ".claude/do-tasks"
FILE_CURRENT_TASK = ".current-task"
FILE_TASK_JSON = "task.json"


def get_project_root() -> str:
    return os.environ.get("CLAUDE_PROJECT_DIR", os.getcwd())


def get_current_task(project_root: str) -> str | None:
    current_task_file = os.path.join(project_root, DIR_TASKS, FILE_CURRENT_TASK)
    if not os.path.exists(current_task_file):
        return None
    try:
        with open(current_task_file, "r", encoding="utf-8") as f:
            content = f.read().strip()
            return content if content else None
    except Exception:
        return None


def read_file_content(base_path: str, file_path: str) -> str | None:
    full_path = os.path.join(base_path, file_path)
    if os.path.exists(full_path) and os.path.isfile(full_path):
        try:
            with open(full_path, "r", encoding="utf-8") as f:
                return f.read()
        except Exception:
            return None
    return None


def read_jsonl_entries(base_path: str, jsonl_path: str) -> list[tuple[str, str]]:
    full_path = os.path.join(base_path, jsonl_path)
    if not os.path.exists(full_path):
        return []

    results = []
    try:
        with open(full_path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    item = json.loads(line)
                    file_path = item.get("file") or item.get("path")
                    if not file_path:
                        continue
                    content = read_file_content(base_path, file_path)
                    if content:
                        results.append((file_path, content))
                except json.JSONDecodeError:
                    continue
    except Exception:
        pass
    return results


def get_agent_context(project_root: str, task_dir: str, agent_type: str) -> str:
    """Get complete context for specified agent."""
    context_parts = []

    # Read agent-specific jsonl
    agent_jsonl = os.path.join(task_dir, f"{agent_type}.jsonl")
    agent_entries = read_jsonl_entries(project_root, agent_jsonl)

    for file_path, content in agent_entries:
        context_parts.append(f"=== {file_path} ===\n{content}")

    # Read prd.md
    prd_content = read_file_content(project_root, os.path.join(task_dir, "prd.md"))
    if prd_content:
        context_parts.append(f"=== {task_dir}/prd.md (Requirements) ===\n{prd_content}")

    return "\n\n".join(context_parts)


def get_task_info(project_root: str, task_dir: str) -> dict | None:
    """Get task.json data."""
    task_json_path = os.path.join(project_root, task_dir, FILE_TASK_JSON)
    if not os.path.exists(task_json_path):
        return None
    try:
        with open(task_json_path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return None


def main():
    import argparse

    parser = argparse.ArgumentParser(description="Get context for current task")
    parser.add_argument("agent", nargs="?", choices=["implement", "check", "debug"],
                        help="Agent type (optional, returns task info if not specified)")
    parser.add_argument("--json", action="store_true", help="Output as JSON")
    args = parser.parse_args()

    project_root = get_project_root()
    task_dir = get_current_task(project_root)

    if not task_dir:
        if args.json:
            print(json.dumps({"error": "No active task"}))
        else:
            print("No active task.", file=sys.stderr)
        sys.exit(1)

    task_info = get_task_info(project_root, task_dir)

    if not args.agent:
        if args.json:
            print(json.dumps({"task_dir": task_dir, "task_info": task_info}))
        else:
            print(f"Task: {task_dir}")
            if task_info:
                print(f"Title: {task_info.get('title', 'N/A')}")
                print(f"Phase: {task_info.get('current_phase', '?')}/{task_info.get('max_phases', 5)}")
        sys.exit(0)

    context = get_agent_context(project_root, task_dir, args.agent)

    if args.json:
        print(json.dumps({
            "task_dir": task_dir,
            "agent": args.agent,
            "context": context,
            "task_info": task_info,
        }))
    else:
        print(context)


if __name__ == "__main__":
    main()

"""Shared utilities for harness hooks.

Consolidates duplicated logic: payload reading, state root discovery,
JSON I/O, lock primitives, task eligibility, and ISO time helpers.

Ported from Codex harness hooks to Claude Code.
"""
from __future__ import annotations

import datetime as _dt
import hashlib
import json
import os
import shutil
import sys
import time
from pathlib import Path
from typing import Any, Optional

# ---------------------------------------------------------------------------
# Time helpers
# ---------------------------------------------------------------------------

def utc_now() -> _dt.datetime:
    return _dt.datetime.now(tz=_dt.timezone.utc)


def iso_z(dt: _dt.datetime) -> str:
    dt = dt.astimezone(_dt.timezone.utc).replace(microsecond=0)
    return dt.isoformat().replace("+00:00", "Z")


def parse_iso(ts: Any) -> Optional[_dt.datetime]:
    if not isinstance(ts, str) or not ts.strip():
        return None
    s = ts.strip()
    if s.endswith("Z"):
        s = s[:-1] + "+00:00"
    try:
        dt = _dt.datetime.fromisoformat(s)
    except Exception:
        return None
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=_dt.timezone.utc)
    return dt.astimezone(_dt.timezone.utc)


# ---------------------------------------------------------------------------
# Hook payload
# ---------------------------------------------------------------------------

def read_hook_payload() -> dict[str, Any]:
    """Read JSON payload from stdin (sent by Claude Code to command hooks)."""
    raw = sys.stdin.read()
    if not raw.strip():
        return {}
    try:
        data = json.loads(raw)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def maybe_log_hook_event(root: Path, payload: dict[str, Any], hook_script: str) -> None:
    """Optionally append a compact hook execution record to HARNESS_HOOK_LOG.

    This is opt-in debugging: when HARNESS_HOOK_LOG is unset, it is a no-op.
    Call this only after the .harness-active guard passes.
    """
    log_path = os.environ.get("HARNESS_HOOK_LOG")
    if not log_path:
        return

    entry: dict[str, Any] = {
        "ts": iso_z(utc_now()),
        "hook_script": hook_script,
        "hook_event_name": payload.get("hook_event_name"),
        "harness_root": str(root),
    }
    for k in (
        "session_id",
        "cwd",
        "source",
        "reason",
        "teammate_name",
        "team_name",
        "agent_id",
        "agent_type",
        "stop_hook_active",
    ):
        if k in payload:
            entry[k] = payload.get(k)

    try:
        Path(log_path).expanduser().parent.mkdir(parents=True, exist_ok=True)
        with Path(log_path).expanduser().open("a", encoding="utf-8") as f:
            f.write(json.dumps(entry, ensure_ascii=False) + "\n")
    except Exception:
        return


# ---------------------------------------------------------------------------
# State root discovery
# ---------------------------------------------------------------------------

def find_harness_root(payload: dict[str, Any]) -> Optional[Path]:
    """Locate the directory containing harness-tasks.json.

    Search order:
    1. HARNESS_STATE_ROOT env var
    2. CLAUDE_PROJECT_DIR env var (+ parents)
    3. payload["cwd"] / os.getcwd() (+ parents)
    """
    env_root = os.environ.get("HARNESS_STATE_ROOT")
    if env_root:
        p = Path(env_root)
        if (p / "harness-tasks.json").is_file():
            try:
                return p.resolve()
            except Exception:
                return p

    candidates: list[Path] = []
    env_dir = os.environ.get("CLAUDE_PROJECT_DIR")
    if env_dir:
        candidates.append(Path(env_dir))
    cwd = payload.get("cwd") or os.getcwd()
    candidates.append(Path(cwd))

    seen: set[str] = set()
    for base in candidates:
        try:
            base = base.resolve()
        except Exception:
            continue
        if str(base) in seen:
            continue
        seen.add(str(base))
        for parent in [base, *list(base.parents)[:8]]:
            if (parent / "harness-tasks.json").is_file():
                return parent
    return None


def is_harness_active(root: Path) -> bool:
    """True when .harness-active marker exists (hooks are live)."""
    return (root / ".harness-active").is_file()


# ---------------------------------------------------------------------------
# JSON I/O
# ---------------------------------------------------------------------------

def load_json(path: Path) -> dict[str, Any]:
    with path.open("r", encoding="utf-8") as f:
        data = json.load(f)
    if not isinstance(data, dict):
        raise ValueError(f"{path.name} must be a JSON object")
    return data


def atomic_write_json(path: Path, data: dict[str, Any]) -> None:
    """Write JSON atomically: backup -> tmp -> rename."""
    bak = path.with_name(f"{path.name}.bak")
    tmp = path.with_name(f"{path.name}.tmp")
    shutil.copy2(path, bak)
    tmp.write_text(
        json.dumps(data, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )
    os.replace(tmp, path)


def tail_text(path: Path, max_bytes: int = 200_000) -> str:
    """Read the last max_bytes of a text file."""
    with path.open("rb") as f:
        try:
            f.seek(0, os.SEEK_END)
            size = f.tell()
            f.seek(max(0, size - max_bytes), os.SEEK_SET)
        except Exception:
            f.seek(0, os.SEEK_SET)
        chunk = f.read()
    return chunk.decode("utf-8", errors="replace")


# ---------------------------------------------------------------------------
# Lock primitives (mkdir-based, POSIX-portable)
# ---------------------------------------------------------------------------

def lockdir_for_root(root: Path) -> Path:
    h = hashlib.sha256(str(root).encode("utf-8")).hexdigest()[:16]
    return Path("/tmp") / f"harness-{h}.lock"


def _pid_alive(pid: int) -> bool:
    try:
        os.kill(pid, 0)
        return True
    except Exception:
        return False


def _read_pid(lockdir: Path) -> Optional[int]:
    try:
        raw = (lockdir / "pid").read_text("utf-8").strip()
        return int(raw) if raw else None
    except Exception:
        return None


def acquire_lock(lockdir: Path, timeout_seconds: float = 5.0) -> None:
    deadline = time.time() + timeout_seconds
    missing_pid_since: Optional[float] = None
    while True:
        try:
            lockdir.mkdir(mode=0o700)
            (lockdir / "pid").write_text(str(os.getpid()), encoding="utf-8")
            return
        except FileExistsError:
            pid = _read_pid(lockdir)
            if pid is None:
                if missing_pid_since is None:
                    missing_pid_since = time.time()
                if time.time() - missing_pid_since < 1.0:
                    if time.time() >= deadline:
                        raise TimeoutError("lock busy (pid missing)")
                    time.sleep(0.05)
                    continue
            else:
                missing_pid_since = None
                if _pid_alive(pid):
                    if time.time() >= deadline:
                        raise TimeoutError(f"lock busy (pid={pid})")
                    time.sleep(0.05)
                    continue

            stale = lockdir.with_name(
                f"{lockdir.name}.stale.{os.getpid()}.{int(time.time())}"
            )
            try:
                lockdir.rename(stale)
            except Exception:
                if time.time() >= deadline:
                    raise TimeoutError("lock contention")
                time.sleep(0.05)
                continue
            shutil.rmtree(stale, ignore_errors=True)
            missing_pid_since = None
            continue


def release_lock(lockdir: Path) -> None:
    shutil.rmtree(lockdir, ignore_errors=True)


# ---------------------------------------------------------------------------
# Task helpers
# ---------------------------------------------------------------------------

def priority_rank(v: Any) -> int:
    return {"P0": 0, "P1": 1, "P2": 2}.get(str(v or ""), 9)


def task_attempts(t: dict[str, Any]) -> int:
    try:
        return int(t.get("attempts") or 0)
    except Exception:
        return 0


def task_max_attempts(t: dict[str, Any]) -> int:
    try:
        v = t.get("max_attempts")
        return int(v) if v is not None else 3
    except Exception:
        return 3


def deps_completed(t: dict[str, Any], completed_ids: set[str]) -> bool:
    deps = t.get("depends_on") or []
    if not isinstance(deps, list):
        return False
    return all(str(d) in completed_ids for d in deps)


def parse_tasks(state: dict[str, Any]) -> list[dict[str, Any]]:
    """Extract validated task list from state dict."""
    tasks_raw = state.get("tasks") or []
    if not isinstance(tasks_raw, list):
        raise ValueError("tasks must be a list")
    return [t for t in tasks_raw if isinstance(t, dict)]


def completed_ids(tasks: list[dict[str, Any]]) -> set[str]:
    return {
        str(t.get("id", ""))
        for t in tasks
        if str(t.get("status", "")) == "completed"
    }


def eligible_tasks(
    tasks: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    """Return (pending_eligible, retryable) sorted by priority then id."""
    done = completed_ids(tasks)

    pending = [
        t for t in tasks
        if str(t.get("status", "")) == "pending" and deps_completed(t, done)
    ]
    retry = [
        t for t in tasks
        if str(t.get("status", "")) == "failed"
        and task_attempts(t) < task_max_attempts(t)
        and deps_completed(t, done)
    ]

    def key(t: dict[str, Any]) -> tuple[int, str]:
        return (priority_rank(t.get("priority")), str(t.get("id", "")))

    pending.sort(key=key)
    retry.sort(key=key)
    return pending, retry


def pick_next(
    pending: list[dict[str, Any]], retry: list[dict[str, Any]]
) -> Optional[dict[str, Any]]:
    return pending[0] if pending else (retry[0] if retry else None)


def status_counts(tasks: list[dict[str, Any]]) -> dict[str, int]:
    counts: dict[str, int] = {}
    for t in tasks:
        s = str(t.get("status") or "pending")
        counts[s] = counts.get(s, 0) + 1
    return counts


def reap_stale_leases(
    tasks: list[dict[str, Any]], now: _dt.datetime
) -> bool:
    """Reset in_progress tasks with expired leases to failed. Returns True if any changed."""
    changed = False
    for t in tasks:
        if str(t.get("status", "")) != "in_progress":
            continue
        exp = parse_iso(t.get("lease_expires_at"))
        if exp is None or exp > now:
            continue

        t["attempts"] = task_attempts(t) + 1
        err = f"[SESSION_TIMEOUT] Lease expired (claimed_by={t.get('claimed_by')})"
        log = t.get("error_log")
        if isinstance(log, list):
            log.append(err)
        else:
            t["error_log"] = [err]

        t["status"] = "failed"
        t.pop("claimed_by", None)
        t.pop("lease_expires_at", None)
        t.pop("claimed_at", None)
        changed = True
    return changed


# ---------------------------------------------------------------------------
# Session config helpers
# ---------------------------------------------------------------------------

def get_session_config(state: dict[str, Any]) -> dict[str, Any]:
    cfg = state.get("session_config") or {}
    return cfg if isinstance(cfg, dict) else {}


def is_concurrent(cfg: dict[str, Any]) -> bool:
    return str(cfg.get("concurrency_mode") or "exclusive") == "concurrent"


# ---------------------------------------------------------------------------
# Hook output helpers
# ---------------------------------------------------------------------------

def emit_block(reason: str) -> None:
    """Print a JSON block decision to stdout and exit 0."""
    print(json.dumps({"decision": "block", "reason": reason}, ensure_ascii=False))


def emit_allow(reason: str = "") -> None:
    """Print a JSON allow decision to stdout and exit 0."""
    out: dict[str, Any] = {"decision": "allow"}
    if reason:
        out["reason"] = reason
    print(json.dumps(out, ensure_ascii=False))


def emit_context(context: str) -> None:
    """Inject additional context via hookSpecificOutput."""
    print(json.dumps(
        {"hookSpecificOutput": {"additionalContext": context}},
        ensure_ascii=False,
    ))


def emit_json(data: dict[str, Any]) -> None:
    """Print arbitrary JSON to stdout."""
    print(json.dumps(data, ensure_ascii=False))

